product_graph:
name: Jacket — 1 unit (3-tier)
goal: >
  Extend the jacket chain to 3 tiers of depth by splitting fiber production
  into raw material extraction and spinning, to support Sankey-style
  contribution tree and hotspot analysis.

functional_unit:
  description: 1 jacket, ready for sale
  amount: 1.0
  unit: unit

units:
  kg: Mass
  unit: Item

products:
  - { name: Raw fiber material, unit: kg }
  - { name: Fiber, unit: kg }
  - { name: Fabric, unit: kg }
  - { name: Zipper, unit: unit }
  - { name: Jacket, unit: unit }

elementary_flows:
  emissions:
    - { name: Carbon dioxide, compartment: air, unit: kg }
    - { name: Methane, compartment: air, unit: kg }
    - { name: Nitrogen oxides, compartment: air, unit: kg }

processes:
  - name: P0 — Raw material extraction
    reference_output: { flow: Raw fiber material, amount: 1.0 }
    emissions:
      - { flow: Carbon dioxide, amount: 1.8 }
      - { flow: Methane, amount: 0.02 }

  - name: P1 — Spinning
    reference_output: { flow: Fiber, amount: 1.0 }
    inputs:
      - { flow: Raw fiber material, amount: 1.2 }
    emissions:
      - { flow: Carbon dioxide, amount: 1.2 }
      - { flow: Methane, amount: 0.01 }

  - name: P2 — Fabric weaving
    reference_output: { flow: Fabric, amount: 1.0 }
    inputs:
      - { flow: Fiber, amount: 1.1 }
    emissions:
      - { flow: Carbon dioxide, amount: 1.5 }
      - { flow: Nitrogen oxides, amount: 0.01 }

  - name: P3 — Zipper production
    reference_output: { flow: Zipper, amount: 1.0 }
    emissions:
      - { flow: Carbon dioxide, amount: 0.4 }
      - { flow: Nitrogen oxides, amount: 0.005 }

  - name: P4 — Jacket assembly
    reference_output: { flow: Jacket, amount: 1.0 }
    inputs:
      - { flow: Fabric, amount: 0.6 }
      - { flow: Zipper, amount: 1.0 }
    emissions:
      - { flow: Carbon dioxide, amount: 0.8 }

reference_process: "P4 — Jacket assembly"

lcia:
  method_name: "TRACI v2.1"
